	authURL, err := GenerateAuthURL(redirectPath, nil, w, r)
	if err != nil {
		http.Error(w, "Failed to generate authorization URL", http.StatusInternalServerError)
		return
	}

	http.Redirect(w, r, authURL, http.StatusTemporaryRedirect)
}

// HandleCallback handles the OAuth2 callback
func HandleCallback(w http.ResponseWriter, r *http.Request) {
	// Verify state parameter
	state := r.URL.Query().Get("state")
	code := r.URL.Query().Get("code")

	if state == "" || code == "" {
		http.Error(w, "Missing state or code parameter", http.StatusBadRequest)
		return
	}

	stateCookie, err := r.Cookie("oauth_state")
	if err != nil {
		http.Error(w, "State cookie not found", http.StatusBadRequest)
		return
	}

	if stateCookie.Value != state {
		http.Error(w, "Invalid state parameter", http.StatusBadRequest)
		return
	}

	// Exchange authorization code for access token
	token, err := OAuthConfig.Exchange(r.Context(), code)
	if err != nil {
		http.Error(w, "Failed to exchange authorization code", http.StatusInternalServerError)
		return
	}

	// Store token in session (example: in a cookie or session store)
	tokenCookie := &http.Cookie{
		Name:     "oauth_token",
		Value:    token.AccessToken,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Expires:  token.Expiry,
	}
	http.SetCookie(w, tokenCookie)

	// Get redirect path from cookie
	redirectCookie, err := r.Cookie("oauth_redirect_path")
	redirectPath := "/"
	if err == nil {
		redirectPath = redirectCookie.Value
	}

	// Clear state and redirect path cookies
	http.SetCookie(w, &http.Cookie{
		Name:   "oauth_state",
		MaxAge: -1,
		Path:   "/",
	})
	http.SetCookie(w, &http.Cookie{
		Name:   "oauth_redirect_path",
		MaxAge: -1,
		Path:   "/",
	})

	http.Redirect(w, r, redirectPath, http.StatusSeeOther)
}

