		TokenURL: "https://provider.com/oauth2/token",
	},
}

// AllowedRedirectHosts defines the whitelist of allowed redirect hosts
var AllowedRedirectHosts = map[string]bool{
	"yourapp.com":       true,
	"localhost:8080":    true,
	"localhost:3000":    true,
}

// generateRandomState generates a cryptographically random state string for CSRF protection
func generateRandomState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", fmt.Errorf("failed to generate random state: %w", err)
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// isValidRedirectURL validates that the redirect URL is safe and whitelisted
func isValidRedirectURL(redirectPath string) bool {
	if redirectPath == "" {
		return false
	}

	// Ensure the redirect path starts with / or is a valid absolute URL
	if !strings.HasPrefix(redirectPath, "/") {
		// If it's an absolute URL, validate the host
		parsedURL, err := url.Parse(redirectPath)
		if err != nil {
			return false
		}

		// Check if the host is in the whitelist
		if !AllowedRedirectHosts[parsedURL.Host] {
			return false
		}

		// Ensure it's HTTPS (or localhost for development)
		if parsedURL.Scheme != "https" && !strings.HasPrefix(parsedURL.Host, "localhost") {
			return false
		}
	}

	return true
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
// It must be a relative path (starting with /) or a whitelisted absolute URL.
func GenerateAuthURL(redirectPath string, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate the redirect path to prevent open redirect attacks
	if !isValidRedirectURL(redirectPath) {
		return "", fmt.Errorf("invalid redirect URL: %s", redirectPath)
	}

	// Generate a cryptographically random state for CSRF protection
	state, err := generateRandomState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Store the state in a secure cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiration
	})

	// Store the redirect path in a separate cookie for retrieval after callback
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_redirect_path",
		Value:    redirectPath,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // 10 minutes expiration
	})

	// Generate the authorization URL using the OAuth config
	authURL := OAuthConfig.AuthCodeURL(state)

	return authURL, nil
}

// ValidateOAuthState validates the state parameter returned from the OAuth provider
func ValidateOAuthState(r *http.Request, returnedState string) (string, error) {
	// Retrieve the state cookie
	cookie, err := r.Cookie("oauth_state")
	if err != nil {
		return "", fmt.Errorf("state cookie not found: %w", err)
	}

	// Compare the returned state with the stored state
	if cookie.Value != returnedState {
		return "", fmt.Errorf("state mismatch: invalid state parameter")
	}

	// Retrieve the redirect path cookie
	redirectCookie, err := r.Cookie("oauth_redirect_path")
	if err != nil {
		return "", fmt.Errorf("redirect path cookie not found: %w", err)
	}

	return redirectCookie.Value, nil
}

