	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return errors.New("invalid redirect URL format")
	}

	// Ensure it's a relative URL or from an allowed host
	if parsedURL.Scheme != "" && parsedURL.Scheme != "https" {
		return errors.New("redirect URL must use https scheme")
	}

	// If it has a host, validate it against allowed hosts
	if parsedURL.Host != "" {
		host := parsedURL.Host
